// Extrair os dados do RSS e preparar para o planejamento
const items = $('Code rss').all();
const slugs = $('Slugs').all();
const titulos = $('Gera Titulo').all();
const metas = $('Gera MetaDescription').all();

const resultados = items.map((item, index) => {

  const slug = slugs[index]?.json.message?.content || 
    item.json.title
      .toLowerCase()
      .normalize("NFD").replace(/[\u0300-\u036f]/g, "")
      .replace(/[^a-z0-9]+/g, "-")
      .replace(/(^-|-$)/g, "");

const titulo = titulos[index]?.json.message?.content || 
    item.json.title
      .toLowerCase()
      .normalize("NFD").replace(/[\u0300-\u036f]/g, "")
      .replace(/[^a-z0-9]+/g, "-")
      .replace(/(^-|-$)/g, "");

const meta_description = metas[index]?.json.message?.content || 
    item.json.title
      .toLowerCase()
      .normalize("NFD").replace(/[\u0300-\u036f]/g, "")
      .replace(/[^a-z0-9]+/g, "-")
      .replace(/(^-|-$)/g, "");  

  return {
	  titulo,
      slug,
      meta_description,
      link: item.json.link     
  };
});

return resultados.slice(0, 4).map(item => ({ json: item }));

