// Concatenate all texts into one field
const result = $input.all().map(item => {
  let allTexts = [];

  if (item.json && item.json.data) {
    item.json.data.forEach(dataItem => {
      if (dataItem.results) {
        dataItem.results.forEach(result => {
          if (result.text) {
            allTexts.push(result.text);
          }
        });
      }
    });
  }

  return {
    fullText: allTexts.join('\n\n')
  };
});

return result;

// Loop over input items and add a new field called 'myNewField' to the JSON of each one
for (const item of $input.all()) {
  item.json.myNewField = 1;
}

return $input.all().slice(0, 4);

const currentSlug = $('Replace Me').first().json.slug;
const titulo = $('Gera Titulo2').first().json.message.content;
const meta_description = $('Replace Me').first().json.meta_description;
const palavra_chave = $('Gera PalavraChave').first().json.message.content;

// PEGAR KEYWORDS
let keywords = $('Set Keyword').all(0).map(i => ({
  slug: i.json.slug,
  titulo: i.json.titulo
}));

// FILTRAR
const usados = new Set();
const filtrados = keywords.filter(k => {
  if (!k.slug) return false;
  if (k.slug === currentSlug) return false;
  if (usados.has(k.slug)) return false;
  usados.add(k.slug);
  return true;
});

// LIMITAR
const selecionados = filtrados.slice(0, 3);

// LISTA
let lista = '';
for (const item of selecionados) {
  lista += `<li><a href="/${item.slug}/" rel="dofollow">${item.titulo}</a></li>`;
}

// FALLBACK
let i = 0;
while (selecionados.length > 0 && (lista.match(/<li>/g) || []).length < 3) {
  const item = selecionados[i % selecionados.length];
  lista += `<li><a href="/${item.slug}/" rel="dofollow">${item.titulo}</a></li>`;
  i++;
}

// =========================
// EXTRAÇÃO ULTRA ROBUSTA
// =========================
let html = '';
let textoBruto = $input.first().json.text;

// 1. Se já for objeto
if (typeof textoBruto === 'object' && textoBruto !== null) {
  html = textoBruto.html || '';
}

// 2. Se for string → tentar parse múltiplas vezes
else if (typeof textoBruto === 'string') {
  let temp = textoBruto;

  for (let i = 0; i < 3; i++) {
    try {
      temp = JSON.parse(temp);
    } catch (e) {
      break;
    }
  }

  if (typeof temp === 'object' && temp !== null) {
    html = temp.html || '';
  } else {
    html = temp;
  }
}

// 3. Fallback
if (!html) {
  html = textoBruto || '';
}

// =========================
// INSERIR LEIA MAIS
// =========================
html = html.replace(/<%leiamais%>/g, lista);

// =========================
// LIMPEZA FINAL (ESSENCIAL)
// =========================
html = html
  .replace(/^\{"html":"/, '')   // remove início bugado
  .replace(/"\}$/, '')          // remove final bugado
  .replace(/\\"/g, '"')         // corrige aspas
  .replace(/\\\\/g, '\\')       // corrige barras
  .trim();

// =========================
// RETURN
// =========================
return {
  titulo,
  meta_description,
  palavra_chave,
  html
};

const metas = items[0].json.data?.[0]?.results || [];

let imagem = "";

for (const meta of metas) {
  const attrs = meta.attributes || [];

  const property = attrs.find(a => a.name === "property");
  const content = attrs.find(a => a.name === "content");

  if (
    property &&
    content &&
    (property.value === "og:image" || property.value === "twitter:image")
  ) {
    imagem = content.value;
    break;
  }
}

return [
  {
    json: {
      maiorImagem: imagem
    }
  }
];

const items = $input.all();
const agora = new Date();
const cincoDias = new Date(agora - 5 * 24 * 60 * 60 * 1000);

// Palavras que indicam conteúdo sem potencial Discover
const rejeitar = [
  'tutor', 'formador', 'professor-formador',
  'cronograma', 'colação de grau', 'aula magna',
  'encerramento', 'seleção de tutor', 'orientador de tcc'
];

const filtrados = [];

for (const item of items) {
  const titulo = (item.json.title || '').toLowerCase();
  const data = new Date(item.json.isoDate);

  // Pular se mais de 5 dias
  if (data < cincoDias) continue;

  // Pular se tem palavra de rejeição
  if (rejeitar.some(r => titulo.includes(r))) continue;

  filtrados.push(item.json);
}

// Montar lista numerada
const listaTitulos = filtrados.map((item, i) => 
  `${i + 1}. ${item.title}`
).join('\n');

return [{
  json: {
    listaTitulos,
    totalFiltrados: filtrados.length,
    todosItems: filtrados
  }
}];

const raw = $input.first().json;

let conteudo;
if (raw.message?.content) {
  conteudo = raw.message.content;
} else if (raw.content) {
  conteudo = raw.content;
} else {
  return [{ json: { erro: 'Não encontrei o content' } }];
}

const limpo = conteudo
  .replace(/```json/g, '')
  .replace(/```/g, '')
  .trim();

const resposta = JSON.parse(limpo);
const indices = resposta.selecionados;
const todos = $('Code rss1').first().json.todosItems;

const resultado = [];
for (let idx = 0; idx < indices.length; idx++) {
  const i = indices[idx];
  const item = todos[i - 1];

  if (item) {
    resultado.push({
      json: {
        title: item.title,
        link: item.link,
        pubDate: item.pubDate,
        contentSnippet: item.contentSnippet,
        motivo: resposta.motivos?.[idx] || '',
        guid: item.guid
      }
    });
  }
}

return resultado;
